const target = 174325986

/**
 * Time Complexity:
 *  - Generating all subarrays: O(n²)
 *  - Total: O(n²)
 *
 * Space Complexity:
 *  - Frequency map: O(n)
 *  - Total: O(n)
 */
function countMajoritySubarrays(nums: number[], target: number): number {
    let count = 0;
    const transformed = nums.map(num => num === target ? +1 : -1)
    const map = new Map<number, number>()
    let prefix = 0;

    map.set(1, 0)

    for (let i = 0; i < transformed.length; i++) {
        prefix += transformed[i]!
        let need = prefix - transformed.length > 0 ? +1 : 0

        if (map.has(need)) {
            map.set(need, (map.get(need) ?? 0) + 1)
            if (map.get(target)! > 0) {
                count++
            }
        } else {
            map.set(need, need)
        }
    }

    return count;
};

console.log(countMajoritySubarrays(nums, target))